using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class EventBookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
}

public class Event
{
    public int Id { get; set; }
    public int AvailableSeats { get; set; }
}

public class TicketService
{
    private readonly EventBookingContext _context;

    public TicketService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int numberOfTickets)
    {
        var @event = await _context.Events
            .FindAsync(eventId);

        if (@event == null || numberOfTickets <= 0 || numberOfTickets > @event.AvailableSeats)
        {
            return false;
        }

        // Use optimistic concurrency control with a row version property (e.g., ConcurrencyToken attribute on AvailableSeats)
        var originalAvailableSeats = @event.AvailableSeats;

        @event.AvailableSeats -= numberOfTickets;

        try
        {
            await _context.SaveChangesAsync();
            return true;
        }
        catch (DbUpdateConcurrencyException ex) when (ex.Entries.Any(e => e.Entity is Event))
        {
            // Handle concurrency conflict, e.g., reload the entity and retry or notify the user
            var entry = ex.Entries.Single(e => e.Entity is Event);
            if (entry.CurrentValues["AvailableSeats"] != originalAvailableSeats)
            {
                // Reload the entity from the database and try again
                await _context.Entry(@event).ReloadAsync();
                return await PurchaseTicketsAsync(eventId, numberOfTickets);
            }
        }

        return false;
    }
}